// Extract the key fields from the ClickUp task payload
const task = items[0].json.task || items[0].json;

const taskId   = task.id;
const taskName = task.name;
const taskDesc = task.description || task.text_content || '';

// Pull any extra context from custom fields
const customFields = (task.custom_fields || []);
const extraContext = customFields
  .filter(f => f.value)
  .map(f => `${f.name}: ${f.value}`)
  .join('\n');

return [{ json: { taskId, taskName, taskDesc, extraContext } }];

// Parse the Glean chat response
const gleanResponse = items[0].json;

// Glean returns messages array; grab the last AGENT message
const messages = gleanResponse.messages || [];
const agentMsg  = [...messages].reverse().find(m => m.author === 'GLEAN_AGENT' || m.role === 'assistant') || messages[messages.length - 1];

// Extract plain text from fragments
let draftText = '';
if (agentMsg?.fragments) {
  draftText = agentMsg.fragments.map(f => f.text || '').join('');
} else if (agentMsg?.content) {
  draftText = agentMsg.content;
} else {
  draftText = JSON.stringify(agentMsg);
}

// Carry forward task context from earlier in the chain
const taskId   = $node["Extract Task Info"].json.taskId;
const taskName = $node["Extract Task Info"].json.taskName;
const taskDesc = $node["Extract Task Info"].json.taskDesc;

return [{ json: { taskId, taskName, taskDesc, draftText } }];
